package com.switchcase;

public class Assignment_Operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10;
		int b=20;
		a+=4;
		System.out.println(a);

		b-=4;
		System.out.println(b);

		a*=4;
		System.out.println(a);

		b*=4;
		System.out.println(b);

		a/=4;
		System.out.println(a);

		b/=4;
		System.out.println(b);

		


	}

}
